// Built-in sound-effect library.
// Data: sound-library/sounds.json + assets/sound-effects/<id>.mp3.
// UI: search + chips(popular/group) + waveform cards with peaks.

export interface SoundEffect {
  id: string;
  name: string;
  group: string;
  seconds: number;
  desc: string;
  popular: boolean;
  order: number;
  /** Precomputed amplitude peaks from 0–1, packed into 96 bins. */
  peaks: number[];
  keywords: string[];
}

export interface SoundGroup { id: string; name: string; nameEn: string; }

