/** public URL for a sound effect's audio file */
export const soundEffectSrc = (id: string): string => `/sound-effects/${id}.mp3`;

export function formatSoundDuration(seconds: number): string {
  if (seconds < 10) return `${seconds.toFixed(1)}s`;
  if (seconds < 60) return `${Math.round(seconds)}s`;
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return `${m}:${String(s).padStart(2, '0')}`;
}

/** downsample peaks to N visual bins (max of each window) */
export function resamplePeaks(peaks: number[], bins: number): number[] {
  if (bins <= 0) return [];
  if (peaks.length === 0) return Array(bins).fill(0);
  if (peaks.length === bins) return peaks.slice();
  const out: number[] = [];
  for (let i = 0; i < bins; i++) {
    const a = Math.floor((i / bins) * peaks.length);
    const b = Math.max(a + 1, Math.floor(((i + 1) / bins) * peaks.length));
    let m = 0;
    for (let j = a; j < b; j++) m = Math.max(m, peaks[j] ?? 0);
    out.push(m);
  }
  return out;
}

/** build an SVG area path for waveform (viewBox 0 0 w h, centered mid) */
export function peaksToPath(peaks: number[], w = 100, h = 32): string {
  if (!peaks.length) return `M0 ${h / 2} L${w} ${h / 2}`;
  const mid = h / 2;
  const n = peaks.length;
  const top: string[] = [];
  const bot: string[] = [];
  for (let i = 0; i < n; i++) {
    const x = (i / Math.max(1, n - 1)) * w;
    const amp = Math.min(1, Math.max(0, peaks[i]!)) * (mid - 1);
    top.push(`${x.toFixed(2)},${(mid - amp).toFixed(2)}`);
    bot.push(`${x.toFixed(2)},${(mid + amp).toFixed(2)}`);
  }
  return `M${top[0]} L${top.slice(1).join(' L')} L${bot.slice().reverse().join(' L')} Z`;
}
